#include <threads.h>
#include <hardware.h>
#include <terminals.h>

#ifndef TERMINAL_MAX_LINE
#define TERMINAL_MAX_LINE 1024
#endif

#ifndef ERROR
#define ERROR (-1)
#endif

#define ECHO_BUF_SIZE 4096

/* Per-terminal state */
static struct {
    int initialized;
    struct termstat stats;

    /* Input buffer (circular) */
    char input_buf[TERMINAL_MAX_LINE];
    int input_head;
    int input_tail;
    int input_count;
    int input_lines;
    int input_partial;

    /* Echo buffer (circular) */
    char echo_buf[ECHO_BUF_SIZE];
    int echo_head;
    int echo_tail;
    int echo_count;

    /* Hardware transmitter state */
    int transmitting;

    /* WriteTerminal state */
    char *write_buf;
    int write_buflen;
    int write_pos;
    int write_active;
    int write_cr_pending;
    int write_done;

    /* Reader state */
    int reader_active;

    /* Condition variables */
    cond_id_t writer_cv;
    cond_id_t writer_queue_cv;
    cond_id_t reader_cv;
    cond_id_t reader_queue_cv;
} terms[NUM_TERMINALS];

static int driver_init = 0;

/*
 * Internal helper: enqueue a character into the echo buffer.
 */
static void
echo_enqueue(int t, char c)
{
    if (terms[t].echo_count < ECHO_BUF_SIZE) {
        terms[t].echo_buf[terms[t].echo_tail] = c;
        terms[t].echo_tail = (terms[t].echo_tail + 1) % ECHO_BUF_SIZE;
        terms[t].echo_count++;
    }
}

/*
 * Internal helper: dequeue a character from the echo buffer.
 */
static char
echo_dequeue(int t)
{
    char c = terms[t].echo_buf[terms[t].echo_head];
    terms[t].echo_head = (terms[t].echo_head + 1) % ECHO_BUF_SIZE;
    terms[t].echo_count--;
    return c;
}

/*
 * Internal helper: try to start output on a terminal.
 * Echo output always has priority over WriteTerminal output.
 */
static void
start_output(int t)
{
    char c;

    if (terms[t].transmitting)
        return;

    /* Echo has priority */
    if (terms[t].echo_count > 0) {
        c = echo_dequeue(t);
        WriteDataRegister(t, c);
        terms[t].stats.tty_out++;
        terms[t].transmitting = 1;
        return;
    }

    /* WriteTerminal output */
    if (terms[t].write_active) {
        if (terms[t].write_cr_pending) {
            /* Send the \n part of a \r\n pair */
            WriteDataRegister(t, '\n');
            terms[t].stats.tty_out++;
            terms[t].transmitting = 1;
            terms[t].write_cr_pending = 0;
            return;
        }
        if (terms[t].write_pos < terms[t].write_buflen) {
            c = terms[t].write_buf[terms[t].write_pos];
            terms[t].write_pos++;
            if (c == '\n') {
                /* Output \n as \r\n */
                WriteDataRegister(t, '\r');
                terms[t].stats.tty_out++;
                terms[t].transmitting = 1;
                terms[t].write_cr_pending = 1;
            } else {
                WriteDataRegister(t, c);
                terms[t].stats.tty_out++;
                terms[t].transmitting = 1;
            }
            return;
        }
        /* All write characters transmitted; write is complete */
        terms[t].write_done = 1;
        CondSignal(terms[t].writer_cv);
    }
}

/* ================================================================
 * Entry Procedures of the Monitor
 * ================================================================ */

int
InitTerminalDriver(void)
{
    int i;
    Declare_Monitor_Entry_Procedure();

    if (driver_init)
        return ERROR;

    for (i = 0; i < NUM_TERMINALS; i++) {
        terms[i].initialized = 0;
        terms[i].stats.tty_in = -1;
        terms[i].stats.tty_out = -1;
        terms[i].stats.user_in = -1;
        terms[i].stats.user_out = -1;

        terms[i].input_head = 0;
        terms[i].input_tail = 0;
        terms[i].input_count = 0;
        terms[i].input_lines = 0;
        terms[i].input_partial = 0;

        terms[i].echo_head = 0;
        terms[i].echo_tail = 0;
        terms[i].echo_count = 0;

        terms[i].transmitting = 0;

        terms[i].write_buf = 0;
        terms[i].write_buflen = 0;
        terms[i].write_pos = 0;
        terms[i].write_active = 0;
        terms[i].write_cr_pending = 0;
        terms[i].write_done = 0;

        terms[i].reader_active = 0;

        terms[i].writer_cv = CondCreate();
        terms[i].writer_queue_cv = CondCreate();
        terms[i].reader_cv = CondCreate();
        terms[i].reader_queue_cv = CondCreate();
    }

    driver_init = 1;
    return 0;
}

int
InitTerminal(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_init)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (terms[term].initialized)
        return ERROR;

    if (InitHardware(term) == ERROR)
        return ERROR;

    terms[term].initialized = 1;
    terms[term].stats.tty_in = 0;
    terms[term].stats.tty_out = 0;
    terms[term].stats.user_in = 0;
    terms[term].stats.user_out = 0;

    return 0;
}

int
WriteTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_init)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (!terms[term].initialized)
        return ERROR;
    if (!buf)
        return ERROR;
    if (buflen < 0)
        return ERROR;
    if (buflen == 0)
        return 0;

    /* Increment user_in stat */
    terms[term].stats.user_in += buflen;

    /* Serialize writers on the same terminal */
    while (terms[term].write_active)
        CondWait(terms[term].writer_queue_cv);

    /* Set up write state */
    terms[term].write_active = 1;
    terms[term].write_buf = buf;
    terms[term].write_buflen = buflen;
    terms[term].write_pos = 0;
    terms[term].write_cr_pending = 0;
    terms[term].write_done = 0;

    /* Kick off output */
    start_output(term);

    /* Wait for all characters to be transmitted */
    while (!terms[term].write_done)
        CondWait(terms[term].writer_cv);

    /* Let the next waiting writer proceed */
    terms[term].write_active = 0;
    CondSignal(terms[term].writer_queue_cv);

    return buflen;
}

int
ReadTerminal(int term, char *buf, int buflen)
{
    int n;
    Declare_Monitor_Entry_Procedure();

    if (!driver_init)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (!terms[term].initialized)
        return ERROR;
    if (!buf)
        return ERROR;
    if (buflen < 0)
        return ERROR;
    if (buflen == 0)
        return 0;

    /* Serialize readers on the same terminal */
    while (terms[term].reader_active)
        CondWait(terms[term].reader_queue_cv);
    terms[term].reader_active = 1;

    /* Block until a complete line or enough characters are available */
    while (terms[term].input_lines == 0 &&
           terms[term].input_count < buflen)
        CondWait(terms[term].reader_cv);

    /* Copy characters to user buffer */
    n = 0;
    while (n < buflen && terms[term].input_count > 0) {
        char c = terms[term].input_buf[terms[term].input_head];
        terms[term].input_head =
            (terms[term].input_head + 1) % TERMINAL_MAX_LINE;
        terms[term].input_count--;
        buf[n++] = c;
        if (c == '\n') {
            terms[term].input_lines--;
            break;
        }
    }

    /* Increment user_out stat */
    terms[term].stats.user_out += n;

    /* Let the next waiting reader proceed */
    terms[term].reader_active = 0;
    CondSignal(terms[term].reader_queue_cv);

    return n;
}

int
TerminalDriverStatistics(struct termstat *stats)
{
    int i;
    Declare_Monitor_Entry_Procedure();

    if (!driver_init)
        return ERROR;
    if (!stats)
        return ERROR;

    for (i = 0; i < NUM_TERMINALS; i++) {
        stats[i] = terms[i].stats;
    }

    return 0;
}

void
ReceiveInterrupt(int term)
{
    char c;
    Declare_Monitor_Entry_Procedure();

    if (!driver_init || term < 0 || term >= NUM_TERMINALS ||
        !terms[term].initialized)
        return;

    c = ReadDataRegister(term);
    terms[term].stats.tty_in++;

    if (c == '\r' || c == '\n') {
        /* Echo \r\n */
        echo_enqueue(term, '\r');
        echo_enqueue(term, '\n');
        /* Store \n in input buffer (completes a line) */
        if (terms[term].input_count < TERMINAL_MAX_LINE) {
            terms[term].input_buf[terms[term].input_tail] = '\n';
            terms[term].input_tail =
                (terms[term].input_tail + 1) % TERMINAL_MAX_LINE;
            terms[term].input_count++;
            terms[term].input_lines++;
            terms[term].input_partial = 0;
        }
        CondSignal(terms[term].reader_cv);
    } else if (c == '\b' || c == '\177') {
        /* Backspace / delete */
        if (terms[term].input_partial > 0) {
            terms[term].input_tail =
                (terms[term].input_tail - 1 + TERMINAL_MAX_LINE) %
                TERMINAL_MAX_LINE;
            terms[term].input_count--;
            terms[term].input_partial--;
            /* Echo: backspace, space, backspace */
            echo_enqueue(term, '\b');
            echo_enqueue(term, ' ');
            echo_enqueue(term, '\b');
        }
    } else {
        /* Regular character */
        if (terms[term].input_count < TERMINAL_MAX_LINE) {
            terms[term].input_buf[terms[term].input_tail] = c;
            terms[term].input_tail =
                (terms[term].input_tail + 1) % TERMINAL_MAX_LINE;
            terms[term].input_count++;
            terms[term].input_partial++;
            echo_enqueue(term, c);
            CondSignal(terms[term].reader_cv);
        }
        /* Buffer full: drop the character */
    }

    /* Start sending echo output if transmitter is idle */
    start_output(term);
}

void
TransmitInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_init || term < 0 || term >= NUM_TERMINALS ||
        !terms[term].initialized)
        return;

    terms[term].transmitting = 0;
    start_output(term);
}

